const e=JSON.parse('{"key":"v-43069acd","path":"/code/Golang/goroutine.html","title":"goroutine","lang":"zh-CN","frontmatter":{"title":"goroutine","order":100,"index":true,"article":true,"description":"以下引于 claude.ai goroutine是Go语言中的轻量级线程。具体来说,goroutine有以下几个主要特征: goroutine由Go运行时(runtime)管理,可以实现高度的并发。一个程序可以同时运行成千上万个goroutine。 goroutine之间通过channel进行通信。channel使得不同goroutine之间可以安全地共享内存。 创建goroutine的代价非常小。因为goroutine的堆栈起始很小(仅2KB),所以可以很容易地创建很多goroutine。 goroutine使用协作式调度(cooperative scheduling),多个goroutine可以在一个或几个操作系统线程上执行。Go运行时内部使用自举调度器在goroutine之间快速切换。 goroutine通信安全。通信和内存同步都隐式实现,不需加锁。 总之,goroutine作为Go并发的核心,使得编写并发程序变得简单、高效。它独特的设计对Go语言的高并发性能起到关键作用。","head":[["meta",{"property":"og:url","content":"https://docs.lizili.online/code/Golang/goroutine.html"}],["meta",{"property":"og:title","content":"goroutine"}],["meta",{"property":"og:description","content":"以下引于 claude.ai goroutine是Go语言中的轻量级线程。具体来说,goroutine有以下几个主要特征: goroutine由Go运行时(runtime)管理,可以实现高度的并发。一个程序可以同时运行成千上万个goroutine。 goroutine之间通过channel进行通信。channel使得不同goroutine之间可以安全地共享内存。 创建goroutine的代价非常小。因为goroutine的堆栈起始很小(仅2KB),所以可以很容易地创建很多goroutine。 goroutine使用协作式调度(cooperative scheduling),多个goroutine可以在一个或几个操作系统线程上执行。Go运行时内部使用自举调度器在goroutine之间快速切换。 goroutine通信安全。通信和内存同步都隐式实现,不需加锁。 总之,goroutine作为Go并发的核心,使得编写并发程序变得简单、高效。它独特的设计对Go语言的高并发性能起到关键作用。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://docs.lizili.online/"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-07-26T07:31:48.000Z"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:image:alt","content":"goroutine"}],["meta",{"property":"article:author","content":"z"}],["meta",{"property":"article:modified_time","content":"2023-07-26T07:31:48.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"goroutine\\",\\"image\\":[\\"https://docs.lizili.online/\\"],\\"dateModified\\":\\"2023-07-26T07:31:48.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"z\\",\\"url\\":\\"https://docs.lizili.online\\"}]}"]]},"headers":[{"level":2,"title":"创建goroutine","slug":"创建goroutine","link":"#创建goroutine","children":[]},{"level":2,"title":"runtime","slug":"runtime","link":"#runtime","children":[{"level":3,"title":"Gosched","slug":"gosched","link":"#gosched","children":[]},{"level":3,"title":"Goexit","slug":"goexit","link":"#goexit","children":[]},{"level":3,"title":"GOMAXPROCS","slug":"gomaxprocs","link":"#gomaxprocs","children":[]}]},{"level":2,"title":"sync.WaitGroup","slug":"sync-waitgroup","link":"#sync-waitgroup","children":[]}],"git":{"createdTime":1690356708000,"updatedTime":1690356708000,"contributors":[{"name":"lizili","email":"cn.zili.lee@outlook.com","commits":1}]},"readingTime":{"minutes":6.5,"words":1950},"filePathRelative":"code/Golang/goroutine.md","localizedDate":"2023年7月26日","excerpt":"<h1> </h1>\\n<blockquote>\\n<p>以下引于 claude.ai</p>\\n</blockquote>\\n<p>goroutine是Go语言中的轻量级线程。具体来说,goroutine有以下几个主要特征:</p>\\n<ol>\\n<li>goroutine由Go运行时(runtime)管理,可以实现高度的并发。一个程序可以同时运行成千上万个goroutine。</li>\\n<li>goroutine之间通过channel进行通信。channel使得不同goroutine之间可以安全地共享内存。</li>\\n<li>创建goroutine的代价非常小。因为goroutine的堆栈起始很小(仅2KB),所以可以很容易地创建很多goroutine。</li>\\n<li>goroutine使用协作式调度(cooperative scheduling),多个goroutine可以在一个或几个操作系统线程上执行。Go运行时内部使用自举调度器在goroutine之间快速切换。</li>\\n<li>goroutine通信安全。通信和内存同步都隐式实现,不需加锁。\\n总之,goroutine作为Go并发的核心,使得编写并发程序变得简单、高效。它独特的设计对Go语言的高并发性能起到关键作用。</li>\\n</ol>","autoDesc":true}');export{e as data};
